var should = require('should');

var Controls = require('../visual/scenario/controls');

function createFakeElement(initialValue) {
    var listeners = {};

    return {
        value: initialValue,
        addEventListener: function(type, cb) {
            listeners[type] = listeners[type] || [];
            listeners[type].push(cb);
        },
        dispatchEvent: function(type) {
            var callbacks = listeners[type] || [];
            callbacks.forEach(function(cb) {
                cb();
            });
        },
        click: function() {
            this.dispatchEvent('click');
        }
    };
}

describe('Scenario controls', function() {
    describe('finder discovery', function() {
        it('should discover public finders from src/finders', function() {
            var finders = Controls.discoverAlgorithms();

            finders.should.containEql('AStarFinder');
            finders.should.containEql('BiDijkstraFinder');
            finders.should.containEql('JumpPointFinder');
            finders.should.containEql('IDAStarFinder');
            finders.should.not.containEql('JumpPointFinderBase');
            finders.length.should.equal(10);
        });
    });

    describe('selection and parsing', function() {
        var controls;
        var algorithmSelect;
        var gridSizeSelect;
        var speedInput;

        beforeEach(function() {
            algorithmSelect = createFakeElement('AStarFinder');
            gridSizeSelect = createFakeElement('15x15');
            speedInput = createFakeElement('300');

            controls = Controls.create({
                algorithmSelect: algorithmSelect,
                gridSizeSelect: gridSizeSelect,
                speedInput: speedInput,
                findPathButton: createFakeElement(''),
                clearButton: createFakeElement('')
            });
        });

        it('should return selected algorithm', function() {
            algorithmSelect.value = 'DijkstraFinder';
            controls.getSelectedAlgorithm().should.equal('DijkstraFinder');
        });

        it('should parse grid size', function() {
            gridSizeSelect.value = '20x30';
            controls.getGridSize().should.eql([20, 30]);
        });

        it('should fallback to 15x15 when grid size is invalid', function() {
            gridSizeSelect.value = 'bad-size';
            controls.getGridSize().should.eql([15, 15]);
        });

        it('should parse speed value as number', function() {
            speedInput.value = '450';
            controls.getSpeed().should.equal(450);
        });

        it('should fallback speed when value is invalid', function() {
            speedInput.value = 'not-a-number';
            controls.getSpeed().should.equal(300);
        });
    });

    describe('events', function() {
        it('should call find-path callbacks on click', function() {
            var findPathButton = createFakeElement('');
            var controls = Controls.create({
