var createScenarioBuilder = require('../visual/scenario/scenario-builder');

describe('ScenarioBuilder', function() {
    it('should create a 15x15 walkable grid by default', function() {
        var builder = createScenarioBuilder();
        var grid = builder.getGrid();

        grid.length.should.equal(15);
        grid[0].length.should.equal(15);
        for (var y = 0; y < 15; ++y) {
            for (var x = 0; x < 15; ++x) {
                grid[y][x].should.equal(0);
            }
        }
    });

    it('should toggle wall state on a cell', function() {
        var builder = createScenarioBuilder();

        builder.toggleWall(3, 4);
        builder.getGrid()[4][3].should.equal(1);

        builder.toggleWall(3, 4);
        builder.getGrid()[4][3].should.equal(0);
    });

    it('should place start and end nodes and keep them walkable', function() {
        var builder = createScenarioBuilder();

        builder.toggleWall(2, 2);
        builder.toggleWall(5, 6);

        builder.placeStart(2, 2);
        builder.placeEnd(5, 6);

        builder.getStart().should.eql({ x: 2, y: 2 });
        builder.getEnd().should.eql({ x: 5, y: 6 });
        builder.getGrid()[2][2].should.equal(0);
        builder.getGrid()[6][5].should.equal(0);
    });

    it('should support setGrid and preserve start/end accessors', function() {
        var builder = createScenarioBuilder();
        var matrix = [
            [0, 1, 0],
            [1, 0, 1],
            [0, 0, 0]
        ];

        builder.setGrid(matrix);

        builder.getGrid().should.eql(matrix);
        builder.getStart().should.eql({ x: 0, y: 0 });
        builder.getEnd().should.eql({ x: 2, y: 2 });
    });

    it('should notify listeners when grid state changes', function() {
        var builder = createScenarioBuilder();
        var calls = 0;
        var lastState;

        builder.onGridChange(function(state) {
            calls += 1;
            lastState = state;
        });

        builder.toggleWall(1, 1);
        builder.placeStart(0, 1);

        calls.should.equal(2);
        lastState.start.should.eql({ x: 0, y: 1 });
        lastState.grid[1][1].should.equal(1);
    });
});

